set -euo pipefail
set -x

# Standard prompt-only math parquet, e.g. generated by examples/data_preprocess/math_dataset.py
train_path=${HYBRID_EIF_ONLINE_TRAIN_PATH:-$HOME/data/math/train.parquet}
val_path=${HYBRID_EIF_ONLINE_VAL_PATH:-$HOME/data/math/test.parquet}

model_path=${HYBRID_EIF_ONLINE_MODEL_PATH:-Qwen/Qwen3-4B-Base}

trainer_gpus=${HYBRID_EIF_ONLINE_TRAINER_GPUS_PER_NODE:-8}
trainer_nodes=${HYBRID_EIF_ONLINE_TRAINER_NNODES:-1}
train_batch_size=${HYBRID_EIF_ONLINE_TRAIN_BATCH_SIZE:-64}
max_prompt_length=${HYBRID_EIF_ONLINE_MAX_PROMPT_LENGTH:-1024}
max_response_length=${HYBRID_EIF_ONLINE_MAX_RESPONSE_LENGTH:-2048}
ppo_mini_batch_size=${HYBRID_EIF_ONLINE_PPO_MINI_BATCH_SIZE:-64}
ppo_micro_batch_size=${HYBRID_EIF_ONLINE_PPO_MICRO_BATCH_SIZE_PER_GPU:-2}
rollout_log_prob_micro_batch_size=${HYBRID_EIF_ONLINE_ROLLOUT_LOG_PROB_MICRO_BATCH_SIZE_PER_GPU:-2}
ref_log_prob_micro_batch_size=${HYBRID_EIF_ONLINE_REF_LOG_PROB_MICRO_BATCH_SIZE_PER_GPU:-2}
rollout_tp_size=${HYBRID_EIF_ONLINE_ROLLOUT_TP_SIZE:-2}
rollout_n=${HYBRID_EIF_ONLINE_ROLLOUT_N:-6}
rollout_gpu_memory_utilization=${HYBRID_EIF_ONLINE_ROLLOUT_GPU_MEMORY_UTILIZATION:-0.5}
rollout_max_num_seqs=${HYBRID_EIF_ONLINE_ROLLOUT_MAX_NUM_SEQS:-128}
rollout_max_num_batched_tokens=${HYBRID_EIF_ONLINE_ROLLOUT_MAX_NUM_BATCHED_TOKENS:-$((max_prompt_length + max_response_length))}

# Set HYBRID_EIF_ONLINE_USE_SEPARATE_TAU=1 to use a separate 32B model for tau_LLM.
# Default (0): aux reward and tau_LLM share the same 7B model on port 8000.
use_separate_tau=${HYBRID_EIF_ONLINE_USE_SEPARATE_TAU:-0}

aux_model=${HYBRID_EIF_ONLINE_AUX_MODEL:-Qwen/Qwen2.5-7B-Instruct}
aux_base_url=${HYBRID_EIF_ONLINE_AUX_BASE_URL:-http://localhost:8000/v1}
aux_api_key_env=${HYBRID_EIF_ONLINE_AUX_API_KEY_ENV:-OPENAI_API_KEY}
aux_temperature=${HYBRID_EIF_ONLINE_AUX_TEMPERATURE:-1.0}
aux_max_tokens=${HYBRID_EIF_ONLINE_AUX_MAX_TOKENS:-16}
aux_concurrency=${HYBRID_EIF_ONLINE_AUX_CONCURRENCY:-32}

if [[ "$use_separate_tau" == "1" ]]; then
    tau_model=${HYBRID_EIF_ONLINE_TAU_MODEL:-Qwen/Qwen2.5-32B-Instruct}
    tau_base_url=${HYBRID_EIF_ONLINE_TAU_BASE_URL:-http://localhost:8001/v1}
else
    tau_model=${HYBRID_EIF_ONLINE_TAU_MODEL:-$aux_model}
    tau_base_url=${HYBRID_EIF_ONLINE_TAU_BASE_URL:-$aux_base_url}
fi
tau_api_key_env=${HYBRID_EIF_ONLINE_TAU_API_KEY_ENV:-OPENAI_API_KEY}
tau_temperature=${HYBRID_EIF_ONLINE_TAU_TEMPERATURE:-0.0}
tau_max_tokens=${HYBRID_EIF_ONLINE_TAU_MAX_TOKENS:-16}
tau_concurrency=${HYBRID_EIF_ONLINE_TAU_CONCURRENCY:-128}

num_aux_samples=${HYBRID_EIF_ONLINE_NUM_AUX_SAMPLES:-4}
experiment_name=${HYBRID_EIF_ONLINE_EXPERIMENT_NAME:-qwen3_4b_hybrid_eif_online}
loggers=${HYBRID_EIF_ONLINE_LOGGERS:-'["console"]'}

for required_path in "$train_path" "$val_path"; do
    if [[ ! -f "$required_path" ]]; then
        echo "Missing online hybrid EIF data file: $required_path" >&2
        exit 1
    fi
done

if (( num_aux_samples < 2 )); then
    echo "HYBRID_EIF_ONLINE_NUM_AUX_SAMPLES must be >= 2, got $num_aux_samples." >&2
    exit 1
fi

python3 -m verl.trainer.main_ppo \
    algorithm.adv_estimator=grpo \
    data.train_files="['$train_path']" \
    data.val_files="['$val_path']" \
    data.train_batch_size="$train_batch_size" \
    data.max_prompt_length="$max_prompt_length" \
    data.max_response_length="$max_response_length" \
    data.filter_overlong_prompts=True \
    data.truncation='error' \
    actor_rollout_ref.model.path="$model_path" \
    actor_rollout_ref.actor.optim.lr=1e-6 \
    actor_rollout_ref.model.use_remove_padding=True \
    actor_rollout_ref.model.enable_gradient_checkpointing=True \
    actor_rollout_ref.actor.ppo_mini_batch_size="$ppo_mini_batch_size" \
    actor_rollout_ref.actor.ppo_micro_batch_size_per_gpu="$ppo_micro_batch_size" \
    actor_rollout_ref.actor.use_kl_loss=True \
    actor_rollout_ref.actor.kl_loss_coef=0.001 \
    actor_rollout_ref.actor.kl_loss_type=low_var_kl \
    actor_rollout_ref.rollout.name=vllm \
    actor_rollout_ref.rollout.gpu_memory_utilization="$rollout_gpu_memory_utilization" \
    actor_rollout_ref.rollout.max_num_seqs="$rollout_max_num_seqs" \
    actor_rollout_ref.rollout.max_num_batched_tokens="$rollout_max_num_batched_tokens" \
    actor_rollout_ref.rollout.log_prob_micro_batch_size_per_gpu="$rollout_log_prob_micro_batch_size" \
    actor_rollout_ref.rollout.tensor_model_parallel_size="$rollout_tp_size" \
    actor_rollout_ref.rollout.n="$rollout_n" \
    actor_rollout_ref.ref.log_prob_micro_batch_size_per_gpu="$ref_log_prob_micro_batch_size" \
    algorithm.use_kl_in_reward=False \
    reward.reward_manager.name=hybrid_eif_online \
    reward.reward_kwargs.hybrid_eif_online.num_aux_samples="$num_aux_samples" \
    reward.reward_kwargs.hybrid_eif_online.aux_model="$aux_model" \
    reward.reward_kwargs.hybrid_eif_online.aux_base_url="$aux_base_url" \
    reward.reward_kwargs.hybrid_eif_online.aux_api_key_env="$aux_api_key_env" \
    reward.reward_kwargs.hybrid_eif_online.aux_temperature="$aux_temperature" \
    reward.reward_kwargs.hybrid_eif_online.aux_max_tokens="$aux_max_tokens" \
    reward.reward_kwargs.hybrid_eif_online.aux_concurrency="$aux_concurrency" \
    reward.reward_kwargs.hybrid_eif_online.tau_model="$tau_model" \
    reward.reward_kwargs.hybrid_eif_online.tau_base_url="$tau_base_url" \
    reward.reward_kwargs.hybrid_eif_online.tau_api_key_env="$tau_api_key_env" \
    reward.reward_kwargs.hybrid_eif_online.tau_temperature="$tau_temperature" \
    reward.reward_kwargs.hybrid_eif_online.tau_max_tokens="$tau_max_tokens" \
    reward.reward_kwargs.hybrid_eif_online.tau_concurrency="$tau_concurrency" \
    trainer.critic_warmup=0 \
    trainer.logger="$loggers" \
    trainer.project_name='verl_hybrid_eif_online_grpo' \
    trainer.experiment_name="$experiment_name" \
    trainer.n_gpus_per_node="$trainer_gpus" \
    trainer.nnodes="$trainer_nodes" \
    trainer.save_freq=20 \
    trainer.test_freq=5 \
    trainer.total_epochs=20 $@
